33		rootCmd := &cobra.Command{Use: "port"}
34		RegisterClear(rootCmd)
35	
36		clearCmd, _, err := rootCmd.Find([]string{"clear"})
37		if err != nil || clearCmd == nil {
38			t.Fatal("clear command not found")
39		}
